INSERT INTO temas_voz_colaboradores (id,nombre,descripcion,exclusivo_para_empresa,created_at,updated_at,deleted_at) VALUES
	 (4,'Conflicto de interés','Cuando un colaborador participa o parece que participa en una actividad o relación que le beneficia a él y no a la empresa.',NULL,'2020-03-03 13:07:14','2021-10-05 21:53:01',NULL),
	 (5,'Acoso laboral','Agresión verbal o psicológica de manera repetida o persistente donde un colaborador o grupo de colaboradores ofenden o humillan a un empleado.',NULL,'2020-03-03 13:08:23','2021-10-05 21:51:51',NULL),
	 (6,'Acoso sexual','Cualquier comportamiento físico o verbal de naturaleza sexual que atente contra la dignidad de una persona; particularmente cuando se crea un entorno laboral intimidatorio, degradante u ofensivo.',NULL,'2020-03-03 13:08:37','2021-10-05 21:52:14',NULL),
	 (7,'Mantenimiento','Si ves algún objeto o equipo de la empresa que esté dañado, por favor avísanos para que podamos arreglarlo a la brevedad posible.',NULL,'2020-03-03 13:08:51','2021-10-05 21:54:18',NULL),
	 (8,'Robo','Si sabes de alguien que haya tomado algún objeto personal o de la compañía sin consentimiento del dueño por favor avísanos para poder hacer la investigación correspondiente.',NULL,'2020-03-03 13:09:02','2021-10-05 21:55:01',NULL),
	 (9,'Discriminación','Cuando un colaborador es tratado de forma distinta respecto al resto de trabajadores por su raza, color, religión, sexo (incluyendo el embarazo, identidad de género y orientación sexual), origen nacional, discapacidad o edad.',NULL,'2020-03-03 13:09:13','2021-10-05 21:53:37',NULL),
	 (10,'Abuso de autoridad','Cuando una persona con cargo superior se excede en el ejercicio de su capacidad o mando para obligar a un colaborador a hacer algo en contra de su voluntad',NULL,'2020-03-03 13:09:27','2021-10-05 21:51:37',NULL),
	 (11,'Otro','Si no encuentras un tema en concreto del cual quieres hablar, utiliza esta opción para hacernos saber lo que piensas.',NULL,'2020-03-03 13:09:33','2021-10-05 21:54:30',NULL),
	 (13,'Clima laboral','Ayúdanos con cualquier sugerencia que tengas para mejorar el ambiente que vivimos entre todos los colaboradores de la empresa. Por ejemplo, ideas que ayuden a mejorar la equidad, el reconocimiento entre los empleados, la evaluación del desempeño, disponibilidad del supervisor / jefe, prestaciones y beneficios.',NULL,'2020-11-20 01:48:40','2021-10-05 21:52:36',NULL),
	 (14,'Salud','Cuéntanos sobre cualquier desviación o anomalía que hayas visto en los protocolos de Salud en la empresa.',NULL,'2021-01-14 22:39:25','2023-11-07 11:00:43',NULL);
INSERT INTO temas_voz_colaboradores (id,nombre,descripcion,exclusivo_para_empresa,created_at,updated_at,deleted_at) VALUES
	 (16,'Agradecimiento','Hazle saber a la empresa acerca de un acontecimiento que quieras agradecerles. Ejemplo: Oportunidades de crecimiento, Beneficios especiales, o cualquier otra cosa que creas que merece ser agradecida.',NULL,'2021-09-13 19:15:11','2021-10-05 21:51:07',NULL),
	 (17,'Higiene y Seguridad','Nuestra prioridad es tu seguridad, ayúdanos reportando actos y/o condiciones inseguras.',NULL,'2023-02-04 18:04:46','2023-02-04 18:04:46',NULL),
	 (18,'Nómina','Reporta cualquier problema relacionado a tus pagos o recibos de nómina.',NULL,'2023-02-10 21:54:18','2023-02-10 21:54:18',NULL),
	 (19,'Innovación','Proporciona ideas para mejorar los procesos internos, optimizar tareas y fomentar la innovación en el entorno laboral.',NULL,'2023-12-19 10:14:48','2024-05-31 14:08:07',NULL),
	 (20,'Innovación','Proporciona ideas para mejorar los procesos internos, optimizar tareas y fomentar la innovación en el entorno laboral.','52','2023-12-19 10:39:22','2023-12-19 10:39:22',NULL),
	 (21,'Bienestar Físico','Enfocada en mejoras para el bienestar físico; sugerencias para equipamiento en áreas de descanso, programas de ejercicio, o cualquier iniciativa que promueva la salud física.','52','2023-12-19 10:42:04','2023-12-19 10:42:04',NULL),
	 (22,'Desarrollo Profesional','Ideas para promover el crecimiento profesional; sugerencias de programas de capacitación, talleres o actividades que contribuyan al desarrollo de habilidades.','52','2023-12-19 10:42:20','2023-12-19 10:42:20',NULL),
	 (23,'Comunicación Interna','Orientada a mejorar la comunicación dentro de la organización, proponiendo métodos más efectivos, herramientas de colaboración, o iniciativas que fortalezcan el intercambio de información.','52','2023-12-19 10:42:41','2023-12-19 10:42:41',NULL),
	 (24,'Reconocimiento y Celebración','Enfocada en sugerencias para reconocer logros individuales o de equipo, así como propuestas para celebrar hitos y eventos importantes en la empresa.','52','2023-12-19 10:43:18','2023-12-19 10:43:18',NULL),
	 (25,'Conciliación Vida-Trabajo','Ideas para mejorar la conciliación entre la vida personal y laboral, como opciones de flexibilidad horaria, programas de apoyo familiar, o iniciativas que promuevan un equilibrio saludable.','52','2023-12-19 10:43:57','2023-12-19 10:43:57',NULL);
INSERT INTO temas_voz_colaboradores (id,nombre,descripcion,exclusivo_para_empresa,created_at,updated_at,deleted_at) VALUES
	 (26,'Diversidad e Inclusión','Propuestas para fortalecer la diversidad y la inclusión en el lugar de trabajo, como programas específicos, eventos, o prácticas que promuevan un ambiente más inclusivo.','52','2023-12-19 10:44:18','2023-12-19 10:44:18',NULL),
	 (27,'Medio Ambiente Laboral','Enfoque en mejoras para el entorno físico y social del trabajo, abarcando desde el diseño de espacios hasta iniciativas que fomenten la colaboración y el compañerismo.','52','2023-12-19 10:44:33','2023-12-19 10:44:33',NULL),
	 (28,'Servicios y Beneficios','Propuestas relacionadas con convenios y beneficios adicionales, que impacten positivamente en la calidad de vida.','52','2023-12-19 10:44:54','2023-12-19 10:44:54',NULL),
	 (29,'Cultura Organizacional','Ideas para fortalecer la cultura organizacional, como eventos culturales, programas de voluntariado, o cualquier iniciativa que contribuya a un ambiente laboral positivo y motivador.','52','2023-12-19 10:45:19','2023-12-19 10:45:19',NULL),
	 (30,'Agradecimientos','Propuestas para establecer mecanismos de reconocimiento y expresión de agradecimientos, fortaleciendo la cultura de aprecio y motivación en el equipo.','52','2023-12-19 10:45:31','2023-12-19 10:45:31',NULL),
	 (31,'Seguridad, Higiene y Mantenimiento','Ideas para mejorar aspectos relacionados con la seguridad laboral y medidas de higiene en el entorno de trabajo, así como mantenimiento y cuidado de instalaciones, equipos y espacios comunes.','52','2023-12-19 10:46:02','2023-12-19 10:46:02',NULL),
	 (35,'Bienestar Físico','Enfocada en mejoras para el bienestar físico; sugerencias para equipamiento en áreas de descanso, programas de ejercicio, o cualquier iniciativa que promueva la salud física.','54','2024-03-05 16:52:38','2024-03-05 16:52:38',NULL),
	 (36,'Desarrollo Profesional','Ideas para promover el crecimiento profesional; sugerencias de programas de capacitación, talleres o actividades que contribuyan al desarrollo de habilidades.','54','2024-03-05 16:54:42','2024-03-05 16:54:42',NULL),
	 (37,'Comunicación Interna','Orientada a mejorar la comunicación dentro de la organización, proponiendo métodos más efectivos, herramientas de colaboración, o iniciativas que fortalezcan el intercambio de información.','54','2024-03-05 16:54:59','2024-03-05 16:54:59',NULL),
	 (38,'Reconocimiento y Celebración','Enfocada en sugerencias para reconocer logros individuales o de equipo, así como propuestas para celebrar hitos y eventos importantes en la empresa.','54','2024-03-05 16:55:16','2024-03-05 16:55:16',NULL);
