	 (40,'Diversidad e Inclusión','Propuestas para fortalecer la diversidad y la inclusión en el lugar de trabajo, como programas específicos, eventos, o prácticas que promuevan un ambiente más inclusivo.','54','2024-03-05 16:55:47','2024-03-05 16:55:47',NULL),
	 (41,'Medio Ambiente Laboral','Enfoque en mejoras para el entorno físico y social del trabajo, abarcando desde el diseño de espacios hasta iniciativas que fomenten la colaboración y el compañerismo.','54','2024-03-05 16:56:02','2024-03-05 16:56:02',NULL),
	 (42,'Servicios y Beneficios','Propuestas relacionadas con convenios y beneficios adicionales, que impacten positivamente en la calidad de vida.','54','2024-03-05 16:56:20','2024-03-05 16:56:20',NULL),
	 (43,'Cultura Organizacional','Ideas para fortalecer la cultura organizacional, como eventos culturales, programas de voluntariado, o cualquier iniciativa que contribuya a un ambiente laboral positivo y motivador.','54','2024-03-05 16:56:37','2024-03-05 16:56:37',NULL),
	 (44,'Agradecimientos','Propuestas para establecer mecanismos de reconocimiento y expresión de agradecimientos, fortaleciendo la cultura de aprecio y motivación en el equipo.','54','2024-03-05 16:56:52','2024-03-05 16:56:52',NULL),
	 (45,'Seguridad, Higiene y Mantenimiento','Ideas para mejorar aspectos relacionados con la seguridad laboral y medidas de higiene en el entorno de trabajo, así como mantenimiento y cuidado de instalaciones, equipos y espacios comunes.','54','2024-03-05 16:57:09','2024-03-05 16:57:09',NULL),
	 (46,'Salud','Orientada a propuestas para promover la salud general de los colaboradores, ya sea a través de programas específicos, iniciativas de bienestar o consejos relacionados con la salud.','54','2024-03-05 16:57:31','2024-03-05 16:57:31',NULL),
	 (47,'"Otro"','Un espacio abierto para cualquier sugerencia que no encaje directamente en las categorías anteriores, brindando libertad para ideas diversas y creativas.','54','2024-03-05 16:58:20','2024-04-05 13:27:20',NULL),
	 (48,'Comedor de Colaboradores','Si tienes algún comentario o felicitación con referencia a los alimentos, limpieza, atención y equipo para tu uso de nuestro comedor de colaboradores (Loza, cubiertos, vasos, charolas, Horno de microondas etc).','51','2024-04-15 10:27:14','2024-04-15 10:27:14',NULL);
INSERT INTO temas_voz_colaboradores (id,nombre,descripcion,exclusivo_para_empresa,created_at,updated_at,deleted_at) VALUES
	 (49,'Baño de Colaboradores','Si tienes algún comentario con referencia a limpieza y condición de las instalaciones de nuestro baño de colaboradores.','51','2024-04-15 10:27:49','2024-04-15 10:27:49',NULL),
	 (50,'Compromiso Ciudadano','Tú decides hacia dónde vamos, gracias por no permitir que eligieran por ti, queremos reconocerte como ciudadano responsable.  Por tal motivo sube por este medio una selfie mostrando tu dedo después de haber votado y estarás participando en una rifa especial. ¡Juntos por la mejora del país, muchas gracias!','51','2024-05-21 15:46:43','2024-05-21 15:46:43',NULL),
	 (51,'Conexión Contigo','Espacio donde podrás compartirnos fotografías, textos y opiniones, para participar en dinámicas que tenemos preparadas para ti.','56','2024-05-31 13:27:44','2024-06-02 08:10:16',NULL),
	 (52,'Compromiso Ciudadano','Tú decides hacia dónde vamos, gracias por no permitir que eligieran por ti, queremos reconocerte como ciudadano responsable.  Por tal motivo sube por este medio una selfie mostrando tu dedo después de haber votado y estarás participando en una rifa especial. ¡Juntos por la mejora del país, muchas gracias!','51','2024-06-02 08:12:35','2024-06-02 08:12:35',NULL),
	 (53,'Voto','CEC agradece y celebra tu compromiso con México. En el cuadro de comentario pon la palabra "Voto" y después adjunta tu selfie con tu pulgar marcado. Da click en enviar (Favor de NO ponerlo como anónimo) y te daremos una sorpresa.','43','2024-06-02 08:21:35','2024-06-02 08:21:35',NULL),
	 (54,'Retroalimentación','La retroalimentación ayuda a mejorar cómo se hacen las tareas diarias en call center. Consiste en recibir comentarios sobre el trabajo para identificar qué se puede hacer mejor, corregir errores y brindar un mejor servicio.','84','2025-02-26 18:43:00','2025-04-30 11:35:25',NULL),
	 (55,'Servicios Generales','Si detectas necesidades relacionadas con limpieza, reposición de suministros (como jabón, papel higiénico, garrafones de agua, etc.) o el orden general en las áreas comunes, por favor avísanos para que podamos atenderlo a la brevedad posible',NULL,'2025-04-30 12:39:57','2025-04-30 17:41:11',NULL);
